#!/usr/bin/env node
/**
 * PreToolUse scope guard (v2) for 系统模式 (UI-update) headless claude runs — cwd = the CODE repo.
 * Registered via {data}/state/settings.system.json (generated by the server).
 *
 * The spawned agent is JAILED to the code repo. Enforced boundaries:
 *   WRITE (Edit/Write/MultiEdit/NotebookEdit)  → only under src/client/   (edit its own UI)
 *   READ  (Read/Grep/Glob)                     → only inside the code repo
 *   BASH                                       → not: git-history / delete, network egress,
 *                                                inline code-eval, filesystem crawl, or any path
 *                                                outside the repo (args or redirects)
 *
 * Anything genuinely out-of-boundary (fetch a URL, run a scraper, read a shared resource) MUST go
 * through a server MCP tool — mediated + auditable — never raw Bash. Everything else: silent exit 0.
 *
 * This body is kept identical to the planner guard (ChatEnvironmentService.ScopeGuardMjs) except for
 * WRITE_DIRS; the e2e suite (p24) runs both. GUARD_VERSION lets the server re-issue newer logic.
 */
// GUARD_VERSION: 2
import path from 'node:path';

const WRITE_DIRS = ['src/client'];

const HISTORY = [
  /\bgit\s+(commit|add|push|reset|restore|checkout|clean|rebase|stash|rm)\b/,
  /\brm\s+-[rf]/, /\bRemove-Item\b/i, /\bdel\s+\/[a-z]/i,
];
const NETWORK = [
  /\bcurl\b/, /\bwget\b/, /\bInvoke-WebRequest\b/i, /(^|[\s;&|(])iwr(\s|$)/i,
  /\bInvoke-RestMethod\b/i, /(^|[\s;&|(])nc(\s|$)/, /\bncat\b/, /\btelnet\b/, /\bssh\b/, /\bscp\b/,
];
const EVALS = [
  /\bnode\s+(-e|--eval)\b/, /\b(python3?|py)\s+-c\b/, /\bperl\s+-e\b/, /\bruby\s+-e\b/,
  /\b(powershell|pwsh)\b[\s\S]*\s-(e|enc|encodedcommand|command)\b/i, /(^|[\s;&|(])eval(\s|$)/,
];
const CRAWL = [
  /(^|[\s;&|(])find\s/, /(^|[\s;&|(])ls\s+-[a-zA-Z]*[Rr]/, /(^|[\s;&|(])dir\b[\s\S]*\/s/i,
];
const HOME = /(\$HOME|\$HOMEPATH|\$USERPROFILE|\$LOCALAPPDATA|\$APPDATA|\$env:|%USERPROFILE%|%LOCALAPPDATA%|%APPDATA%|%HOMEPATH%)/i;

function deny(reason) {
  process.stdout.write(JSON.stringify({
    hookSpecificOutput: { hookEventName: 'PreToolUse', permissionDecision: 'deny', permissionDecisionReason: reason },
  }));
  process.exit(0);
}
const allow = () => process.exit(0);

// Normalize a path (relative → resolved against `root`) to a lowercased, drive-aware slash form so
// containment is a string-prefix test. Git-bash `/c/x` and Windows `C:\x` both fold to `c:/x`.
function norm(p, root) {
  let s = String(p).replace(/\\/g, '/').replace(/^\/([A-Za-z])(?=\/|$)/, (_, d) => `${d}:`);
  const abs = /^[A-Za-z]:/.test(s) || s.startsWith('/');
  if (!abs) s = `${String(root).replace(/\\/g, '/')}/${s}`;
  const out = [];
  for (const seg of s.split('/')) {
    if (seg === '' || seg === '.') continue;
    if (seg === '..') out.pop(); else out.push(seg);
  }
  return out.join('/').toLowerCase();
}
// Relative path of `p` inside `root`, or null when `p` escapes it.
function relTo(p, root) {
  const r = norm('.', root);
  const n = norm(p, root);
  if (n === r) return '';
  if (n.startsWith(r + '/')) return n.slice(r.length + 1);
  return null;
}
const inside = (p, root) => relTo(p, root) !== null;

// Best-effort: does any path-like token in a Bash command point outside the jail? The robust controls
// are the network/eval denials above + the read/write jail at the tool layer; this catches the common
// cat/cp/mv/redirect-to-outside cases. An OS-level sandbox is the belt-and-suspenders upgrade, and it
// is also what would contain code executed *inside* an agent-authored script (which no hook can see).
function bashEscapes(command, root) {
  if (HOME.test(command)) return true;
  for (let t of command.split(/[\s;|&()<>]+/)) {
    t = t.replace(/^["']+|["']+$/g, '');
    if (!t || t.startsWith('-')) continue;                    // a flag, not a path
    if (/^[a-z][a-z0-9+.-]*:\/\//i.test(t)) continue;         // URL — network already denied
    if (t.startsWith('~')) return true;                       // home dir
    if (t === '..') return true;                              // bare `cd ..` climbing out
    if (!/[\/\\]/.test(t) && !/^[A-Za-z]:$/.test(t)) continue; // not path-like
    if (!inside(t, root)) return true;
  }
  return false;
}

const chunks = [];
for await (const c of process.stdin) chunks.push(c);
let payload;
try { payload = JSON.parse(Buffer.concat(chunks).toString('utf8') || '{}'); } catch { allow(); }

const toolName = payload.tool_name ?? '';
const toolInput = payload.tool_input ?? {};
const projectDir = payload.cwd || process.env.CLAUDE_PROJECT_DIR || process.cwd();

if (toolName === 'Bash') {
  const command = String(toolInput.command ?? '');
  if (HISTORY.some((re) => re.test(command)))
    deny('Blocked: no git-history / destructive commands in 系统模式 — the server commits after you approve the diff.');
  if (NETWORK.some((re) => re.test(command)))
    deny('Blocked: no direct network access from the shell. Use WebFetch / WebSearch, or a server MCP tool for out-of-boundary fetches.');
  if (EVALS.some((re) => re.test(command)))
    deny('Blocked: no inline code-eval (node -e / python -c / powershell -Command). Run a committed script or use an MCP tool.');
  if (CRAWL.some((re) => re.test(command)))
    deny('Blocked: use Read / Glob / Grep to explore — not Bash crawling (find / ls -R / dir /s).');
  if (bashEscapes(command, projectDir))
    deny('Blocked: this command references a path outside the repo. 系统模式 is jailed here; use an MCP tool for anything out-of-boundary.');
  allow();
}

if (toolName === 'Read' || toolName === 'Grep' || toolName === 'Glob') {
  const p = toolInput.file_path ?? toolInput.path ?? '';     // Grep/Glob path is optional (absent = cwd, in jail)
  if (p && !inside(String(p), projectDir))
    deny(`Blocked: reads are limited to the repo — "${p}" is outside it. Use an MCP tool for out-of-boundary data.`);
  allow();
}

if (['Edit', 'Write', 'MultiEdit', 'NotebookEdit'].includes(toolName)) {
  const filePath = toolInput.file_path ?? toolInput.notebook_path ?? toolInput.path ?? '';
  if (!filePath) allow();
  const rel = relTo(filePath, projectDir);
  if (rel === null) deny(`Blocked: ${filePath} is outside the repo.`);
  if (!WRITE_DIRS.some((d) => rel === d || rel.startsWith(d + '/')))
    deny(`Blocked: 系统模式 may only edit ${WRITE_DIRS.join(', ')} — not "${rel}".`);
  allow();
}

allow();
